var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"왕이시여.","JPN":"王よ。","ENG":"My queen.","TWN":"王啊，"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"거대한 방주가 세월을 거슬러, 당신의 낙원을 짓밟기 위해 맹진해오고 있나이다.","JPN":"巨大な箱舟が時を遡り、あなたの楽園を踏みにじるために猛進してきております。","ENG":"A massive Ark is surging back through time, charging straight toward your paradise to trample it.","TWN":"一艘巨大的方舟正逆流歲月而來，即將踐踏你的樂園。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"파노라마 위에 안배해 둔 실이 끊어졌더군요.","JPN":"パノラマの上に仕掛けておいた糸が切れていました。","ENG":"The thread I had arranged upon the Panorama has been severed.","TWN":"我在全景上安排的那條線被切斷了。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"아스모데우스의 짓이겠죠. 그 실을 태울 수 있는 건 그녀의 불꽃 뿐이니까.","JPN":"アスモデウスの仕業でしょう。あの糸を燃やせるのは彼女の炎だけですから。","ENG":"It must be Asmodeus' doing. Only her flames could burn that thread.","TWN":"應該是阿斯蒙蒂斯做的吧，只有她的火焰能燒斷那條線。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"신임할 수 없는 자입니다. 방만하고 호전적이지요.","JPN":"信用できない者です。放漫かつ好戦的すぎます。","ENG":"She is not someone to be trusted. Careless and belligerent.","TWN":"那個人並不值得信任，性情散漫又好戰。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"하지만 발키리의 숙적이기도 하죠.","JPN":"ですが、ヴァルキリーの宿敵でもあります。","ENG":"But she is also the Valkyrie's nemesis.","TWN":"但她同時也是女武神的宿敵。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"제가 그자에게 바라는 건 한 가지 뿐이에요.","JPN":"私があの者に望むのはただ一つだけです。","ENG":"There is only one thing I ask of her.","TWN":"我對那個人只抱有一個期待。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그 뒤에 남는 것은... 모두 제가 감내해야 할 테니까요.","JPN":"後はすべて……私が受け入れるべきものですから。","ENG":"As for what follows after that... I will bear it all myself.","TWN":"至於之後留下的一切……都必須由我來承受。"},"stage":{"bg":"VOID","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뭐지?!","JPN":"何だ！？","ENG":"What was that?!","TWN":"什麼？！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"터널 진로로부터 고강도 차원압 발생!","JPN":"トンネル進路方向より高強度の次元圧発生！","ENG":"High-intensity dimensional pressure detected from the tunnel's route!","TWN":"隧道航線上出現高強度次元壓力！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"방금 충격으로 동행 중이던 수송선 1기가 대파됐습니다!","JPN":"今の衝撃で、同行していた輸送船1隻が大破しました！","ENG":"One of the transport ships accompanying us has just been destroyed by the impact!","TWN":"剛才的衝擊讓同行的一艘運輸船完全毀壞！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"그건 뭐였죠? 너무 순식간이라 보이지도 않았는데?!","JPN":"あれは何だったんですか？　一瞬すぎて何も見えませんでしたが！？","ENG":"What was that? It happened so fast I couldn't even see it!","TWN":"那是什麼？太快了，根本看不見？！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"...차원압 발생지의 에너지 형태를 분석해 이미지화하는 중.","JPN":"……次元圧発生地のエネルギー形態を分析し、画像化中。","ENG":"...Analyzing the energy form at the dimensional pressure source and converting it into an image.","TWN":"……正在分析次元壓力來源的能量形態並進行影像化。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"저건... 인형 팔이잖아?","JPN":"あれは……人形の腕？","ENG":"That's... a doll's arm?","TWN":"那不是……人偶的手臂嗎？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"...타기리온. 그 녀석이 개입하기 시작한 거야.","JPN":"……タギリオン。あいつが介入し出したんだ。","ENG":"...Thagirion. She's started to interfere.","TWN":"……塔基里翁，那傢伙開始介入了。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"다시 옵니다! 저희 함선을 노리고 있어요!","JPN":"もう一度来ます！　私たちの艦船を狙っています！","ENG":"It's coming again! It's targeting our ship!","TWN":"又來了！目標是我們的艦船！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"회피 기동이 가능한 수준이 아니잖아, 이건!","JPN":"回避起動ができるレベルじゃないよ、これは！","ENG":"This isn't something we can evade with normal maneuvering!","TWN":"這根本閃避不了吧！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"꺄아앗?!","JPN":"きゃああっ！？","ENG":"Kyaah?!","TWN":"呀啊？！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"방금 뭐였죠? 저희 함선의 좌표가... 잠시 바뀐 건가요?","JPN":"今のは？　この艦船の座標が……一瞬変わった？","ENG":"What was that just now? Our ship's coordinates... did they change for a moment?","TWN":"剛剛那是什麼？我們的艦船座標……好像突然改變了？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"놀라게 했다면 미안하군.","JPN":"すまない、驚かせてしまったか。","ENG":"My apologies if that startled you.","TWN":"抱歉嚇到你們了。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"가르강튀아가 차원통로에서도 잘 작동해줘서 다행이야.","JPN":"ガルガンティアが次元通路でも上手く動いてくれてよかった。","ENG":"I'm glad Garguantia is functioning well even within the dimensional passage.","TWN":"幸好加爾剛迪亞在次元通道裡也能正常運作。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"마리아 아줌마!","JPN":"マリアおばさん！","ENG":"Maria!","TWN":"瑪麗亞阿姨！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"델타세븐 분들이 지원을 온 건가요?","JPN":"デルタセブンの方々が応援に来てくださったんですか？","ENG":"Has Delta Seven come to support us?","TWN":"第七三角洲部隊的人來支援了嗎？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"더 많은 수를 기대했다면 유감일세. 자네가 아는 얼굴들 중엔 나 뿐일 거야.","JPN":"もっと大人数を期待したなら、謝っておこう。君の見知った顔はおそらく私だけだ。","ENG":"If you were expecting more, I'm afraid I'm the only familiar face you'll see.","TWN":"如果你們期待更多人，那可要失望了。你認識的人大概只有我。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"따라오겠다고 고집 부리는 녀석도 있었지만... 누군가는 우리가 돌아갈 고향을 지켜야 하니 말이지.","JPN":"ついて来ると意地を張る奴もいたが……誰かは私たちの帰る場所を守らねばならないからな。","ENG":"There were others who insisted on coming along... but someone has to guard the place we must return to.","TWN":"雖然也有人堅持要跟來……但總得有人守著我們要回去的地方。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"그러니, 화력 지원은 어렵지만- 자네들이 이 난관을 무사히 피할 수 있도록 도움을 주러 왔네.","JPN":"だから、火力支援は難しいが……君たちがこの難関を無事に乗り越えられるよう、力を貸しに来た。","ENG":"So while I can't provide fire support, I came to help ensure you can safely avoid this danger.","TWN":"所以雖然無法提供火力支援－但我會幫你們避開這場危機。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};